/*
输入
排序
按照题目要求进行模拟
输出结果 
*/ 
#include <bits/stdc++.h>
#define int long long
using namespace std;
int n;
struct Edge {
	int Left, Right;
};
Edge a[1005];
bool cmp (Edge x, Edge y) {
	return x.Left * x.Right < y.Left * y.Right;
}
vector <int> left_hand;
vector <int> ans (1, 0);
vector <int> multiply (vector <int> num, int x) {
	vector <int> digit;
	int carry = 0;
	for (int u : num) {
		int product = u * x + carry;
		digit.push_back (product % 10);
		carry = product / 10;
	}
	while (carry > 0) {
		digit.push_back (carry % 10);
		carry /= 10;
	}
	return digit;
}
bool greaterThan (vector <int> a1, vector <int> a2) {
	if (a1.size() > a2.size()) {
		return true;
	}
	if (a1.size() < a2.size()) {
		return false;
	}
	for (int i = a1.size() - 1; i >= 0; i--) {
		if (a1[i] == a2[i]) {
			continue;
		}
		return a1[i] > a2[i];
	}
	return false;
}
vector <int> divide (vector <int> num, int x) {
	vector <int> digit;
	int borrow = 0;
	for (int i = num.size() - 1; i >= 0; i--) {
		int u = num[i];
		int at_presant = borrow * 10 + u;
		digit.push_back (at_presant / x);
		borrow = at_presant % x;
	}
	reverse (digit.begin(), digit.end());
	while (digit.size() && digit.back() == 0) {
		digit.pop_back ();
	}
	if (digit.empty()) {
		digit.push_back (0);
	}
	return digit;
}
signed main() {
	cin >> n;
	for (int i = 0; i <= n; i++) {
		cin >> a[i].Left >> a[i].Right;
	}
	sort (a + 1, a + n + 1, cmp);
	int tmp = a[0].Left;
	while (tmp) {
		left_hand.push_back (tmp % 10);
		tmp /= 10;
	}
	if (left_hand.empty()) {
		left_hand.push_back (0);
	}
	for (int i = 1; i <= n; i++) {
		vector <int> word = divide (left_hand, a[i].Right);
		if (greaterThan (word, ans)) {
			ans = word;
		}
		left_hand = multiply (left_hand, a[i].Left);
	}
	if (ans.empty()) {
		cout << 0;
		return 0;
	}
	for (int i = ans.size() - 1; i >= 0; i--) {
		int x = ans[i];
		cout << x;
	}
	return 0;
}
